package codegen

import (
	"fmt"
	"io"
	"reflect"
	"sort"
	"strings"
	"time"

	"github.com/consensys/linea-monorepo/prover-ray/wiop"
)

// Options controls the output of [Generate].
type Options struct {
	// Package is the Go package name written into the generated file header.
	Package string
	// FuncName is the name of the generated prove function (default: "Prove").
	FuncName string
	// Imports is the list of additional import paths needed by the generated
	// file beyond the wiop package itself.
	Imports []string
}

// Generate writes a flat Go source file to w that encodes the prover execution
// sequence of sys. Each registered [wiop.ProverAction] and [wiop.VerifierAction]
// is emitted as a direct method call, with round boundaries and action names
// made explicit via comments.
//
// sys must be fully compiled (all compiler passes complete) before calling
// Generate. Callers populate the generated package-level variables in an
// init() function, typically by building the System once at program start.
func Generate(sys *wiop.System, vars ActionVars, opts Options, w io.Writer) error {
	if opts.FuncName == "" {
		opts.FuncName = "Prove"
	}
	if opts.Package == "" {
		opts.Package = "prover"
	}

	cw := &CodeWriter{}

	// Collect extra import paths from the concrete action types.
	extraImports := collectActionImports(vars)
	allImports := dedup(append([]string{
		"fmt",
		"github.com/consensys/linea-monorepo/prover-ray/wiop",
	}, append(extraImports, opts.Imports...)...))
	sort.Strings(allImports)

	// --- file header ---
	cw.Line("// Code generated by wiop/codegen on %s. DO NOT EDIT.", time.Now().UTC().Format(time.RFC3339))
	cw.Line("// Regenerate with: go generate ./wiop/codegen")
	cw.Blank()
	cw.Line("package %s", opts.Package)
	cw.Blank()

	// --- imports ---
	cw.Line("import (")
	cw.In()
	for _, imp := range allImports {
		cw.Line("%q", imp)
	}
	cw.Out()
	cw.Line(")")
	cw.Blank()

	// --- package-level action variables (sorted for determinism) ---
	cw.Line("// Action variables are populated by the caller's init() function.")
	cw.Line("var (")
	cw.In()
	for _, entry := range vars.sortedProver() {
		cw.Line("%s %s", entry.name, concreteTypeName(entry.act))
	}
	for _, entry := range vars.sortedVerifier() {
		cw.Line("%s %s", entry.name, concreteTypeName(entry.act))
	}
	cw.Out()
	cw.Line(")")
	cw.Blank()

	// --- Prove function ---
	cw.Line("// %s executes all prover rounds and verifier checks in declaration order.", opts.FuncName)
	cw.Line("// It is the canonical entry point for proof generation.")
	cw.Line("func %s(rt *wiop.Runtime) error {", opts.FuncName)
	cw.In()

	for i, r := range sys.Rounds {
		cw.Blank()
		cw.Line("// === Round %d ===", i)

		for _, act := range r.ProverActions {
			cw.Line("%s.Run(rt)", vars.proverVar(act))
		}

		for _, act := range r.VerifierActions {
			cw.Line("if err := %s.Check(rt); err != nil {", vars.verifierVar(act))
			cw.In()
			cw.Line("return fmt.Errorf(\"round %d verifier: %%w\", err)", i)
			cw.Out()
			cw.Line("}")
		}

		cw.Line("rt.AdvanceRound()")
	}

	cw.Blank()
	cw.Line("return nil")
	cw.Out()
	cw.Line("}")

	_, err := cw.WriteTo(w)
	return err
}

// ActionVars maps concrete action pointers to stable Go variable names.
// Build one with [NewActionVars] after compiling the System.
type ActionVars struct {
	prover   map[wiop.ProverAction]string
	verifier map[wiop.VerifierAction]string
	counter  int
}

// NewActionVars creates an empty ActionVars registry.
func NewActionVars() ActionVars {
	return ActionVars{
		prover:   make(map[wiop.ProverAction]string),
		verifier: make(map[wiop.VerifierAction]string),
	}
}

// AddProver registers a prover action with the given variable name.
func (v *ActionVars) AddProver(name string, act wiop.ProverAction) { v.prover[act] = name }

// AddVerifier registers a verifier action with the given variable name.
func (v *ActionVars) AddVerifier(name string, act wiop.VerifierAction) { v.verifier[act] = name }

// CollectFrom walks sys and assigns auto-generated variable names to every
// action not already registered. Names follow the pattern _actN / _checkN.
func (v *ActionVars) CollectFrom(sys *wiop.System) {
	for _, r := range sys.Rounds {
		for _, act := range r.ProverActions {
			if _, ok := v.prover[act]; !ok {
				v.counter++
				v.prover[act] = fmt.Sprintf("_act%d", v.counter)
			}
		}
		for _, act := range r.VerifierActions {
			if _, ok := v.verifier[act]; !ok {
				v.counter++
				v.verifier[act] = fmt.Sprintf("_check%d", v.counter)
			}
		}
	}
}

func (v *ActionVars) proverVar(act wiop.ProverAction) string     { return v.prover[act] }
func (v *ActionVars) verifierVar(act wiop.VerifierAction) string { return v.verifier[act] }

type namedProver struct {
	name string
	act  wiop.ProverAction
}

type namedVerifier struct {
	name string
	act  wiop.VerifierAction
}

func (v *ActionVars) sortedProver() []namedProver {
	out := make([]namedProver, 0, len(v.prover))
	for act, name := range v.prover {
		out = append(out, namedProver{name, act})
	}
	sort.Slice(out, func(i, j int) bool { return out[i].name < out[j].name })
	return out
}

func (v *ActionVars) sortedVerifier() []namedVerifier {
	out := make([]namedVerifier, 0, len(v.verifier))
	for act, name := range v.verifier {
		out = append(out, namedVerifier{name, act})
	}
	sort.Slice(out, func(i, j int) bool { return out[i].name < out[j].name })
	return out
}

// concreteTypeName returns a Go type expression using the short package alias.
// For *pkg.Type it returns "*alias.Type" where alias is the last path segment.
func concreteTypeName(v any) string {
	t := reflect.TypeOf(v)
	if t.Kind() == reflect.Ptr {
		alias := pkgAlias(t.Elem().PkgPath())
		if alias == "" {
			return "*" + t.Elem().Name()
		}
		return "*" + alias + "." + t.Elem().Name()
	}
	return t.String()
}

// collectActionImports returns the import paths of all concrete action types.
func collectActionImports(vars ActionVars) []string {
	seen := make(map[string]bool)
	add := func(v any) {
		t := reflect.TypeOf(v)
		if t.Kind() == reflect.Ptr {
			path := t.Elem().PkgPath()
			if path != "" {
				seen[path] = true
			}
		}
	}
	for act := range vars.prover {
		add(act)
	}
	for act := range vars.verifier {
		add(act)
	}
	out := make([]string, 0, len(seen))
	for p := range seen {
		out = append(out, p)
	}
	return out
}

func pkgAlias(pkgPath string) string {
	if pkgPath == "" {
		return ""
	}
	parts := strings.Split(pkgPath, "/")
	return parts[len(parts)-1]
}

func dedup(ss []string) []string {
	seen := make(map[string]bool, len(ss))
	out := ss[:0:0]
	for _, s := range ss {
		if !seen[s] {
			seen[s] = true
			out = append(out, s)
		}
	}
	return out
}
